# Медленный вариант — O(n) времени, O(1) памяти
def has_duplicates_slow(lst):
    for i in range(len(lst)):
        for j in range(i + 1, len(lst)):
            if lst[i] == lst[j]:
                return True
    return False

# Быстрый вариант — O(n) времени, O(n) памяти
def has_duplicates_fast(lst):
    seen = set()  # Доп. память для множества
    for item in lst:
        if item in seen:
            return True
        seen.add(item)
    return False

