# Практический пример: проверка скобок
def check_brackets(expression):
    stack = []
    pairs = {")": "(", "]": "[", "}": "{"}

    for char in expression:
        if char in "([{":
            stack.append(char)  # Открывающая — кладём в стек
        elif char in ")]}":
            if not stack or stack[-1] != pairs[char]:
                return False  # Нет пары!
            stack.pop()  # Нашли пару — убираем

    return len(stack) == 0  # Стек должен быть пуст

print(check_brackets("(a + b) * [c - d]"))  # True
print(check_brackets("((a + b)"))            # False
print(check_brackets("{[}]"))                # False

# Факториал: n! = n × (n-1) × (n-2) × ... × 1
def factorial(n):
    # Базовый случай: 1! = 1 (или 0! = 1)
    if n <= 1:
        return 1

    # Рекурсивный случай: n! = n × (n-1)!
    return n * factorial(n - 1)

print(factorial(5))  # 120
# 5! = 5 × 4! = 5 × 4 × 3! = 5 × 4 × 3 × 2! = 5 × 4 × 3 × 2 × 1 = 120

# Простое возведение в степень — O(n)
def power_simple(base, exp):
    if exp == 0:
        return 1
    return base * power_simple(base, exp - 1)

# Быстрое возведение в степень — O(log n)
def power_fast(base, exp):
    if exp == 0:
        return 1
    if exp % 2 == 0:  # Чётная степень
        half = power_fast(base, exp // 2)
        return half * half
    else:  # Нечётная степень
        return base * power_fast(base, exp - 1)

print(power_simple(2, 10))  # 1024
print(power_fast(2, 10))    # 1024

# Упражнение: длина списка рекурсивно
def recursive_len(lst):
    if lst == []:
        return 0
    return 1 + recursive_len(lst[1:])

# Упражнение: максимум списка рекурсивно
def recursive_max(lst):
    if len(lst) == 1:
        return lst[0]
    rest_max = recursive_max(lst[1:])
    return lst[0] if lst[0] > rest_max else rest_max

