# Числа Трибоначчи: каждое = сумма трёх предыдущих
@lru_cache(maxsize=None)
def tribonacci(n):
    if n <= 0: return 0
    if n <= 2: return 1
    return tribonacci(n-1) + tribonacci(n-2) + tribonacci(n-3)

