# Числа Каталана: C(n) = сумма C(i)*C(n-1-i) для i от 0 до n-1
@lru_cache(maxsize=None)
def catalan(n):
    if n <= 1: return 1
    return sum(catalan(i) * catalan(n-1-i) for i in range(n))

# 1, 1, 2, 5, 14, 42, 132...
