# НЕ хвостовая рекурсия — после вызова ещё нужно умножить
def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)  # Ещё надо умножить на n!

# Хвостовая рекурсия — вызов последний, ничего после
def factorial_tail(n, accumulator=1):
    if n <= 1:
        return accumulator
    return factorial_tail(n - 1, n * accumulator)  # Всё готово!

print(factorial(5))            # 120
print(factorial_tail(5))       # 120

