def binary_search_answer(lo, hi, check):
    """Находит минимальное значение x в [lo, hi], для которого check(x) = True.
    Предполагаем: check монотонна — False, False, ..., True, True, ..."""
    while lo < hi:
        mid = (lo + hi) // 2
        if check(mid):
            hi = mid       # mid подходит, но может есть меньше
        else:
            lo = mid + 1   # mid не подходит, ищем правее
    return lo

def min_time(n, k, t):
    """n задач, k работников, каждый тратит t минут на задачу."""
    def can_finish(time):
        tasks_done = k * (time // t)
        return tasks_done >= n

    lo, hi = 0, n * t  # максимум: один работник делает всё
    while lo < hi:
        mid = (lo + hi) // 2
        if can_finish(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo

