def max_rope_length(ropes, k):
    """Максимальная длина куска, чтобы нарезать >= k кусков."""
    def can_cut(length):
        if length == 0:
            return True
        pieces = sum(r // length for r in ropes)
        return pieces >= k

    lo, hi = 1, max(ropes)
    result = 0
    while lo <= hi:
        mid = (lo + hi) // 2
        if can_cut(mid):
            result = mid   # mid подходит, но может есть длиннее
            lo = mid + 1
        else:
            hi = mid - 1
    return result

