def find_min(node):
    """Находим минимальный узел (самый левый)"""
    while node.left:
        node = node.left
    return node

def delete(node, value):
    """Удаление значения из BST"""
    if node is None:
        return None

    if value < node.value:
        node.left = delete(node.left, value)
    elif value > node.value:
        node.right = delete(node.right, value)
    else:
        # Случай 1: лист или один потомок
        if node.left is None:
            return node.right
        if node.right is None:
            return node.left
        # Случай 3: два потомка
        successor = find_min(node.right)
        node.value = successor.value
        node.right = delete(node.right, successor.value)

    return node

def inorder(node):
    """In-order обход BST выдаёт отсортированную последовательность"""
    if node is None:
        return []
    return inorder(node.left) + [node.value] + inorder(node.right)

