def topological_sort_dfs(graph, all_vertices):
    """Топологическая сортировка через DFS."""
    visited = set()
    stack = []

    def dfs(v):
        visited.add(v)
        for neighbor in graph.get(v, []):
            if neighbor not in visited:
                dfs(neighbor)
        stack.append(v)  # добавляем ПОСЛЕ обработки потомков

    for v in all_vertices:
        if v not in visited:
            dfs(v)

    return stack[::-1]  # разворачиваем

