import math

def floyd_warshall(n, edges):
    """Floyd-Warshall: кратчайшие пути между всеми парами."""
    INF = math.inf
    dist = [[INF] * n for _ in range(n)]
    nxt = [[None] * n for _ in range(n)]  # для восстановления пути

    for i in range(n):
        dist[i][i] = 0

    for u, v, w in edges:
        dist[u][v] = w
        nxt[u][v] = v

    # Тройной цикл — сердце алгоритма
    for k in range(n):
        for i in range(n):
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]
                    nxt[i][j] = nxt[i][k]

    return dist, nxt

