# Сверху вниз: рекурсия + мемоизация
def fib_top_down(n, memo={}):
    if n <= 1:
        return n
    if n not in memo:
        memo[n] = fib_top_down(n - 1, memo) + fib_top_down(n - 2, memo)
    return memo[n]

