def tsp(dist):
    n = len(dist)
    INF = float('inf')
    # dp[mask][i] — мин. стоимость, посетили mask, сейчас в i
    dp = [[INF] * n for _ in range(1 << n)]
    dp[1][0] = 0  # Начинаем в городе 0

    for mask in range(1 << n):
        for i in range(n):
            if dp[mask][i] == INF:
                continue
            if not (mask >> i) & 1:
                continue
            # Пробуем пойти в непосещённый город j
            for j in range(n):
                if (mask >> j) & 1:
                    continue  # Уже посещён
                new_mask = mask | (1 << j)
                new_cost = dp[mask][i] + dist[i][j]
                if new_cost < dp[new_mask][j]:
                    dp[new_mask][j] = new_cost

    # Возвращаемся в город 0
    full_mask = (1 << n) - 1
    return min(dp[full_mask][i] + dist[i][0] for i in range(n))

