dsu.union(0, 1)  # {0, 1}, {2}, {3}, {4}, {5}
dsu.union(2, 3)  # {0, 1}, {2, 3}, {4}, {5}
dsu.union(1, 3)  # {0, 1, 2, 3}, {4}, {5}

print(dsu.connected(0, 2))  # True — в одном множестве
print(dsu.connected(0, 4))  # False — в разных

dsu.union(4, 5)  # {0, 1, 2, 3}, {4, 5}
print(dsu.connected(4, 5))  # True

def count_components(n, edges):
    dsu = DSU(n)
    components = n
    for u, v in edges:
        if dsu.union(u, v):
            components -= 1
    return components

