def naive_search(text, pattern):
    n, m = len(text), len(pattern)
    positions = []
    for i in range(n - m + 1):
        if text[i:i + m] == pattern:
            positions.append(i)
    return positions

print(naive_search("abcabcabc", "abc"))  # [0, 3, 6]
# В худшем случае ("aaa...a", "aaa...ab") — O(n*m)

def prefix_function(s):
    n = len(s)
    pi = [0] * n
    for i in range(1, n):
        k = pi[i - 1]
        while k > 0 and s[i] != s[k]:
            k = pi[k - 1]
        if s[i] == s[k]:
            k += 1
        pi[i] = k
    return pi

def kmp_search(text, pattern):
    s = pattern + "#" + text  # Разделитель, не входящий в алфавит
    pi = prefix_function(s)
    m = len(pattern)
    positions = []
    for i in range(m + 1, len(s)):
        if pi[i] == m:
            positions.append(i - 2 * m)
    return positions

print(kmp_search("abcabcabc", "abc"))  # [0, 3, 6]

def z_function(s):
    n = len(s)
    z = [0] * n
    z[0] = n
    l, r = 0, 0
    for i in range(1, n):
        if i < r:
            z[i] = min(r - i, z[i - l])
        while i + z[i] < n and s[z[i]] == s[i + z[i]]:
            z[i] += 1
        if i + z[i] > r:
            l, r = i, i + z[i]
    return z

def z_search(text, pattern):
    s = pattern + "#" + text
    z = z_function(s)
    m = len(pattern)
    return [i - m - 1 for i in range(m + 1, len(s)) if z[i] == m]

print(z_search("abcabcabc", "abc"))  # [0, 3, 6]

def rabin_karp(text, pattern):
    n, m = len(text), len(pattern)
    if m > n:
        return []

    BASE, MOD = 31, 10**9 + 9
    power = pow(BASE, m - 1, MOD)

    def hash_str(s):
        h = 0
        for ch in s:
            h = (h * BASE + ord(ch)) % MOD
        return h

    pat_hash = hash_str(pattern)
    win_hash = hash_str(text[:m])
    positions = []

    for i in range(n - m + 1):
        if win_hash == pat_hash and text[i:i + m] == pattern:
            positions.append(i)
        if i + m < n:
            win_hash = (win_hash - ord(text[i]) * power) % MOD
            win_hash = (win_hash * BASE + ord(text[i + m])) % MOD

    return positions

print(rabin_karp("abcabcabc", "abc"))  # [0, 3, 6]

import math

class SqrtDecomposition:
    def __init__(self, arr):
        self.arr = arr[:]
        self.n = len(arr)
        self.block_size = max(1, int(math.isqrt(self.n)))
        self.num_blocks = (self.n + self.block_size - 1) // self.block_size
        self.blocks = [0] * self.num_blocks
        for i in range(self.n):
            self.blocks[i // self.block_size] += arr[i]

    def update(self, idx, val):
        block = idx // self.block_size
        self.blocks[block] += val - self.arr[idx]
        self.arr[idx] = val

    def query(self, l, r):
        total = 0
        bl = l // self.block_size
        br = r // self.block_size

        if bl == br:
            for i in range(l, r + 1):
                total += self.arr[i]
        else:
            # Левый хвост
            for i in range(l, (bl + 1) * self.block_size):
                total += self.arr[i]
            # Целые блоки
            for b in range(bl + 1, br):
                total += self.blocks[b]
            # Правый хвост
            for i in range(br * self.block_size, r + 1):
                total += self.arr[i]

        return total

class SqrtMin:
    def __init__(self, arr):
        self.arr = arr[:]
        self.n = len(arr)
        self.B = max(1, int(math.isqrt(self.n)))
        self.num_blocks = (self.n + self.B - 1) // self.B
        self.block_min = [float('inf')] * self.num_blocks
        for i in range(self.n):
            b = i // self.B
            self.block_min[b] = min(self.block_min[b], arr[i])

    def update(self, idx, val):
        self.arr[idx] = val
        b = idx // self.B
        start = b * self.B
        end = min(start + self.B, self.n)
        self.block_min[b] = min(self.arr[start:end])

    def query(self, l, r):
        res = float('inf')
        bl, br = l // self.B, r // self.B
        if bl == br:
            return min(self.arr[l:r + 1])
        for i in range(l, (bl + 1) * self.B):
            res = min(res, self.arr[i])
        for b in range(bl + 1, br):
            res = min(res, self.block_min[b])
        for i in range(br * self.B, r + 1):
            res = min(res, self.arr[i])
        return res

from collections import deque, defaultdict

def edmonds_karp(n, edges, source, sink):
    graph = defaultdict(lambda: defaultdict(int))
    for u, v, cap in edges:
        graph[u][v] += cap

    def bfs(source, sink, parent):
        visited = {source}
        queue = deque([source])
        while queue:
            u = queue.popleft()
            for v in graph[u]:
                if v not in visited and graph[u][v] > 0:
                    visited.add(v)
                    parent[v] = u
                    if v == sink:
                        return True
                    queue.append(v)
        return False

    total_flow = 0
    while True:
        parent = {}
        if not bfs(source, sink, parent):
            break

        # Находим минимальную пропускную способность на пути
        path_flow = float('inf')
        v = sink
        while v != source:
            u = parent[v]
            path_flow = min(path_flow, graph[u][v])
            v = u

        # Обновляем остаточную сеть
        v = sink
        while v != source:
            u = parent[v]
            graph[u][v] -= path_flow
            graph[v][u] += path_flow
            v = u

        total_flow += path_flow

    return total_flow

